using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }

    [Required, StringLength(100)]
    public string Title { get; set; } = string.Empty;

    [Required]
    public string Category { get; set; } = string.Empty;

    [Required]
    public string Ingredients { get; set; } = string.Empty;

    [Required]
    public string Steps { get; set; } = string.Empty;

    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    // Tracks individual ratings per recipe: recipeId -> list of ratings
    private readonly Dictionary<int, List<int>> _ratings = new();

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes over the dough.\n4. Tear mozzarella and distribute evenly.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                AverageRating = 4.5, RatingCount = 12 },
            new() { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-sear chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Add cream and cooked chicken.\n6. Simmer 10 more minutes. Serve with rice.",
                AverageRating = 4.8, RatingCount = 25 },
            new() { Id = 3, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef\nTaco shells\nLettuce\nTomato\nCheddar cheese\nSour cream\nTaco seasoning\nOnion",
                Steps = "1. Brown ground beef with diced onion.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm taco shells in oven.\n4. Fill shells with beef.\n5. Top with lettuce, tomato, cheese, and sour cream.",
                AverageRating = 4.2, RatingCount = 18 },
            new() { Id = 4, Title = "Pad Thai", Category = "Asian",
                Ingredients = "Rice noodles\nShrimp or tofu\nEgg\nBean sprouts\nGreen onion\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar",
                Steps = "1. Soak rice noodles in warm water for 30 min.\n2. Make sauce: mix tamarind paste, fish sauce, and sugar.\n3. Stir-fry shrimp or tofu until cooked.\n4. Push aside, scramble egg in the pan.\n5. Add drained noodles and sauce, toss together.\n6. Top with bean sprouts, peanuts, green onion, and lime.",
                AverageRating = 4.6, RatingCount = 14 },
            new() { Id = 5, Title = "Spaghetti Carbonara", Category = "Italian",
                Ingredients = "Spaghetti\nPancetta\nEggs\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted boiling water.\n2. Crisp pancetta in a skillet.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Drain pasta, reserving some water.\n5. Toss hot pasta with pancetta, then egg mixture.\n6. Stir quickly so eggs form a creamy sauce (don't scramble).",
                AverageRating = 4.7, RatingCount = 30 },
            new() { Id = 6, Title = "Chocolate Chip Cookies", Category = "Desserts",
                Ingredients = "Butter\nSugar\nBrown sugar\nEggs\nVanilla\nFlour\nBaking soda\nSalt\nChocolate chips",
                Steps = "1. Cream butter and sugars until fluffy.\n2. Beat in eggs and vanilla.\n3. Mix flour, baking soda, and salt, then combine with wet ingredients.\n4. Fold in chocolate chips.\n5. Scoop onto baking sheet.\n6. Bake at 375°F (190°C) for 9-11 minutes.",
                AverageRating = 4.9, RatingCount = 42 },
            new() { Id = 7, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nCilantro\nOnion\nTomato\nJalapeño\nSalt\nGarlic",
                Steps = "1. Halve and pit avocados, scoop into a bowl.\n2. Mash to desired consistency.\n3. Stir in diced onion, tomato, jalapeño, and garlic.\n4. Add lime juice and chopped cilantro.\n5. Season with salt. Serve immediately with chips.",
                AverageRating = 4.4, RatingCount = 20 },
            new() { Id = 8, Title = "Miso Soup", Category = "Asian",
                Ingredients = "Dashi stock\nMiso paste\nTofu\nWakame seaweed\nGreen onion",
                Steps = "1. Bring dashi stock to a simmer.\n2. Add cubed tofu and wakame.\n3. Remove from heat.\n4. Dissolve miso paste into the broth (don't boil after adding miso).\n5. Garnish with sliced green onion.",
                AverageRating = 4.3, RatingCount = 11 },
        };
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
        {
            // Seed with existing aggregate data
            _ratings[recipeId] = [];
            for (int i = 0; i < recipe.RatingCount; i++)
                _ratings[recipeId].Add((int)Math.Round(recipe.AverageRating));
        }

        _ratings[recipeId].Add(stars);
        recipe.RatingCount = _ratings[recipeId].Count;
        recipe.AverageRating = Math.Round(_ratings[recipeId].Average(), 1);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }
}

