@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <div class="mb-4">
        <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><strong>Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@inject RecipeShare.Services.RecipeService RecipeService

<div>
    <span class="me-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button"
                  style="cursor:pointer; font-size:1.5rem; color: @(star <= SelectedRating ? "#ffc107" : "#dee2e6")"
                  @onclick="() => Rate(star)"
                  title="@star star(s)">
                ★
            </span>
        }
    </span>

    @if (Recipe is not null)
    {
        <span class="text-muted">
            @Recipe.AverageRating.ToString("0.0") avg · @Recipe.RatingCount ratings
            @if (JustRated)
            {
                <span class="text-success ms-2">✓ Thanks for rating!</span>
            }
        </span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }
    private int SelectedRating;
    private bool JustRated;

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }

    private void Rate(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SelectedRating = stars;
        JustRated = true;
        Recipe = RecipeService.GetById(RecipeId);
    }
}

