@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<strong>@Model.Title</strong>" has been added.
        <a href="recipe/@SubmittedId">View it here</a> or
        <button class="btn btn-link p-0" @onclick="Reset">submit another</button>.
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe" class="mt-3">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => Model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="5"
                           placeholder="One ingredient per line" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6"
                           placeholder="Describe each step..." />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeShare.Models.Recipe Model { get; set; } = new();
    private bool Submitted;
    private int SubmittedId;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(Model);
        SubmittedId = Model.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Model = new();
        Submitted = false;
    }
}

